protected final JsonDeserializer<Object> _findDeserializer(DeserializationContext ctxt, String typeId) throws IOException {
    JsonDeserializer<Object> deser = _deserializers.get(typeId);
    if (deser == null) {
        /* As per [databind#305], need to provide contextual info. But for backwards compatibility, let's start by only supporting this for base class, not via interface. Later on we can add this to the interface, assuming deprecation at base class helps. */
        JavaType type = _idResolver.typeFromId(ctxt, typeId);
        if (type == null) {
            type = ctxt.constructType(Object.class);
        }
        /* 16-Dec-2010, tatu: Since nominal type we get here has no (generic) type parameters, we actually now need to explicitly narrow from base type (which may have parameterization) using raw type. */
        if ((_baseType != null) && _baseType.getClass() == type.getClass()) {
            /* 09-Aug-2015, tatu: Not sure if the second part of the check makes sense; it appears to check that JavaType impl class is the same which is important for some reason? */
            if (!type.hasGenericTypes()) {
                type = ctxt.getTypeFactory().constructSpecializedType(_baseType, type.getRawClass());
            }
        }
        deser = ctxt.findContextualValueDeserializer(type, _property);
    }
    _deserializers.put(typeId, deser);
    return deser;
}
